-- Snapshot tool: builds the full highlight table for selected schemes
-- and writes deterministic Lua dumps to tests/fixtures/snapshots/<scheme>.lua.
--
-- Purpose: golden baseline for parity verification across the tinted8 migration.
-- Run before the migration to capture the current behavior; run again afterward
-- and diff the snapshot files to confirm zero regression.
--
-- Usage:
--   nvim --headless -u NONE --cmd "set rtp+=$PWD" \
--        -c "luafile tests/fixtures/snapshot_highlights.lua" -c "quit"

local schemes = {
    "base16-tomorrow-night",
    "base16-gruvbox-dark-medium",
    "base16-ia-light",
    "base24-ayu-dark",
}

-- Deterministic Lua serializer: sorted keys, stable formatting, diff-friendly.
local function is_identifier(s)
    return type(s) == "string" and s:match("^[%a_][%w_]*$") ~= nil
end

local function format_key(k)
    if is_identifier(k) then
        return k
    end
    if type(k) == "string" then
        return "[" .. string.format("%q", k) .. "]"
    end
    return "[" .. tostring(k) .. "]"
end

local function serialize(v, indent)
    indent = indent or 0
    if type(v) == "string" then
        return string.format("%q", v)
    end
    if type(v) == "number" or type(v) == "boolean" then
        return tostring(v)
    end
    if type(v) ~= "table" then
        return string.format("%q", tostring(v))
    end

    local pad = string.rep("    ", indent + 1)
    local close_pad = string.rep("    ", indent)

    -- Separate sequence keys from string keys for stable ordering.
    local string_keys = {}
    for k in pairs(v) do
        if type(k) == "string" then
            table.insert(string_keys, k)
        end
    end
    table.sort(string_keys)

    if #string_keys == 0 then
        return "{}"
    end

    local lines = { "{" }
    for _, k in ipairs(string_keys) do
        table.insert(lines, pad .. format_key(k) .. " = " .. serialize(v[k], indent + 1) .. ",")
    end
    table.insert(lines, close_pad .. "}")
    return table.concat(lines, "\n")
end

-- Standardized cfg with all integrations enabled to maximize coverage.
local cfg = {
    default_scheme = "base16-tomorrow-night",
    capabilities = {
        undercurl = true,
        terminal_colors = true,
    },
    ui = {
        transparent = false,
        dim_inactive = false,
    },
    highlights = {
        integrations = {
            telescope = true,
            notify = true,
            cmp = true,
            blink = true,
            dapui = true,
            lualine = true,
        },
    },
}

local colors_mod = require("tinted-nvim.colors")
local highlights_mod = require("tinted-nvim.highlights")

for _, scheme in ipairs(schemes) do
    local palette = colors_mod.resolve(scheme, cfg)
    local hls = highlights_mod.build(palette, cfg)

    local out_path = "tests/fixtures/snapshots/" .. scheme .. ".lua"
    local f = assert(io.open(out_path, "w"))
    f:write("-- Snapshot of highlight build output for " .. scheme .. ".\n")
    f:write("-- Generated by tests/fixtures/snapshot_highlights.lua.\n")
    f:write("-- This is a parity baseline for the tinted8 migration; do not edit by hand.\n\n")
    f:write("return " .. serialize(hls) .. "\n")
    f:close()
    print("wrote " .. out_path)
end
